import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useNavTitle, useAppToast } from '@linm-soft-org/linm-web-common-components';
import { Button, Input, Slideout, TableCard } from '../../ui';
import {
  jobsService,
  type DataSyncSetConfigItem,
  type ExternalConnectorOptions,
  type ExternalConnectorTestConnectResult,
  type ExternalConnectorTestSearchResult,
  type ExternalConnectorPreviewResult,
  type TestExternalConnectorRequest,
  type UpdateDataSyncSetConfigRequest,
} from '../../services/jobs';
import ExternalConnectorConfigForm from './ExternalConnectorConfigForm';
import ExternalConnectorPreviewPanel from './ExternalConnectorPreviewPanel';
import ExternalConnectorListGrid from './ExternalConnectorListGrid';
import JobsListToolbar from './JobsListToolbar';
import {
  filterConnectorRows,
  toConnectorListRow,
  type ConnectorListRow,
} from './externalConnectorListUtils';
import {
  buildOptionsForSave,
  defaultConnectorOptions,
  parseConnectorOptions,
  resolveSyncDateRange,
  stripApiKeyFromOptions,
  validateConnectionDraft,
  serializeConnectorOptions,
  type SyncDateRange,
} from './externalConnectorFormUtils';
import { type ConnectorConfigPanel } from './connectorConfigTooltips';
import styles from './DataSyncSetConfigPage.module.css';
import listStyles from './JobInternalPage.module.css';

const SLIDEOUT_WIDTH = '720px';

type TestResponseState =
  | { kind: 'connect'; result: ExternalConnectorTestConnectResult }
  | { kind: 'search'; result: ExternalConnectorTestSearchResult };

const DataSyncSetConfigPage: React.FC = () => {
  useNavTitle('Cấu hình sync REVA FM');
  const toast = useAppToast();
  const navigate = useNavigate();
  const [rows, setRows] = React.useState<DataSyncSetConfigItem[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [editing, setEditing] = React.useState<DataSyncSetConfigItem | null>(null);
  const [form, setForm] = React.useState<UpdateDataSyncSetConfigRequest>({ isEnabled: true });
  const [options, setOptions] = React.useState<ExternalConnectorOptions>(defaultConnectorOptions());
  const [apiKeyInput, setApiKeyInput] = React.useState('');
  const [hasStoredApiKey, setHasStoredApiKey] = React.useState(false);
  const [activePanel, setActivePanel] = React.useState<ConnectorConfigPanel>('connection');
  const [testFromDate, setTestFromDate] = React.useState('');
  const [testToDate, setTestToDate] = React.useState('');
  const [testResponse, setTestResponse] = React.useState<TestResponseState | null>(null);
  const [syncTarget, setSyncTarget] = React.useState<DataSyncSetConfigItem | null>(null);
  const [syncFromDate, setSyncFromDate] = React.useState('');
  const [syncToDate, setSyncToDate] = React.useState('');
  const [saving, setSaving] = React.useState(false);
  const [running, setRunning] = React.useState(false);
  const [testingConnect, setTestingConnect] = React.useState(false);
  const [testingSearch, setTestingSearch] = React.useState(false);
  const [testingPreview, setTestingPreview] = React.useState(false);
  const [previewResult, setPreviewResult] = React.useState<ExternalConnectorPreviewResult | null>(null);
  const [previewDocumentKey, setPreviewDocumentKey] = React.useState<string | null>(null);
  const [searchQuery, setSearchQuery] = React.useState('');
  const [lastSuccessfulTestByKey, setLastSuccessfulTestByKey] = React.useState<
    Record<string, SyncDateRange & { totalItems: number }>
  >({});
  const [syncDateSource, setSyncDateSource] = React.useState<
    'override' | 'lastTest' | 'default' | 'offset' | null
  >(null);

  const listRows = React.useMemo(() => rows.map(toConnectorListRow), [rows]);
  const filteredRows = React.useMemo(
    () => filterConnectorRows(listRows, searchQuery),
    [listRows, searchQuery],
  );

  const load = React.useCallback(() => {
    setLoading(true);
    jobsService
      .getExternalSetConfigs()
      .then(setRows)
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoading(false));
  }, [toast]);

  React.useEffect(() => load(), [load]);

  const closeEdit = () => {
    setEditing(null);
    setTestResponse(null);
    setPreviewResult(null);
    setPreviewDocumentKey(null);
  };

  const startEdit = (row: ConnectorListRow | DataSyncSetConfigItem) => {
    setSyncTarget(null);
    setTestResponse(null);
    setPreviewResult(null);
    setPreviewDocumentKey(null);
    setEditing(row);
    setApiKeyInput('');
    setActivePanel('connection');
    setForm({
      isEnabled: row.isEnabled,
      externalBaseUrl: row.externalBaseUrl ?? '',
      endpointRouteTemplate: row.endpointRouteTemplate ?? '',
      chunkSize: row.chunkSize,
    });
    const parsed = parseConnectorOptions(row.optionsJson);
    const { options: optClean } = stripApiKeyFromOptions(parsed);
    setHasStoredApiKey(Boolean(row.hasApiKey) || Boolean(parsed.apiKey?.trim()));
    setOptions(optClean);
    const range = resolveSyncDateRange(parsed, null, lastSuccessfulTestByKey[row.configKey] ?? null);
    setTestFromDate(range?.from ?? '');
    setTestToDate(range?.to ?? '');
  };

  const openSyncRequest = (
    row: ConnectorListRow | DataSyncSetConfigItem,
    dateOverride?: SyncDateRange | null,
  ) => {
    const opt = parseConnectorOptions(row.optionsJson);
    if (!row.externalBaseUrl?.trim() || !opt.searchPath?.trim()) {
      toast.error('Cấu hình Base URL và Search path trong Sửa trước khi tạo sync.');
      return;
    }
    if (!row.hasApiKey) {
      toast.error('Cấu hình API key trong Sửa trước khi tạo sync.');
      return;
    }

    const testOverride =
      editing?.configKey === row.configKey && testFromDate && testToDate
        ? { from: testFromDate, to: testToDate }
        : null;

    const range = resolveSyncDateRange(
      opt,
      dateOverride ?? testOverride,
      lastSuccessfulTestByKey[row.configKey] ?? null,
    );
    if (!range) {
      toast.error('Cấu hình Từ ngày / Đến ngày mặc định (hoặc offset + lookback) trong Sửa.');
      setSyncFromDate('');
      setSyncToDate('');
      setSyncDateSource(null);
      return;
    }

    setEditing(null);
    setSyncTarget(row);
    setSyncFromDate(range.from);
    setSyncToDate(range.to);
    setSyncDateSource(dateOverride ?? testOverride ? 'override' : range.source);
  };

  const openSyncWithTestDates = () => {
    if (!editing) return;
    if (!testFromDate || !testToDate) {
      toast.error('Chọn Từ ngày và Đến ngày test trước');
      return;
    }
    if (testFromDate > testToDate) {
      toast.error('Từ ngày không được lớn hơn Đến ngày');
      return;
    }
    if (!hasStoredApiKey && !buildOptionsForSave(options, apiKeyInput, editing.optionsJson, hasStoredApiKey).apiKey) {
      toast.error('Lưu API key trước khi tạo sync (job dùng cấu hình đã Lưu, không dùng draft test).');
      return;
    }
    openSyncRequest(editing, { from: testFromDate, to: testToDate });
  };

  const assertConnectionDraft = (): boolean => {
    const result = validateConnectionDraft(
      form.externalBaseUrl,
      options,
      apiKeyInput,
      editing?.optionsJson,
      hasStoredApiKey,
    );
    if (!result.ok) {
      toast.error(result.message);
      return false;
    }
    return true;
  };

  const assertForTestSearch = (): boolean => {
    if (!assertConnectionDraft()) return false;
    if (!testFromDate || !testToDate) {
      toast.error('Chọn Từ ngày và Đến ngày để test search');
      return false;
    }
    if (testFromDate > testToDate) {
      toast.error('Từ ngày không được lớn hơn Đến ngày');
      return false;
    }
    return true;
  };

  const buildTestRequest = (): TestExternalConnectorRequest => {
    const merged = buildOptionsForSave(options, apiKeyInput, editing?.optionsJson, hasStoredApiKey);
    const resolvedKey = merged.apiKey?.trim() || null;
    return {
      externalBaseUrl: form.externalBaseUrl,
      optionsJson: serializeConnectorOptions(merged),
      apiKey: resolvedKey,
      fromDate: testFromDate || null,
      toDate: testToDate || null,
      pageSize: 5,
    };
  };

  const runTestConnect = async () => {
    if (!editing || !assertConnectionDraft()) return;
    setTestingConnect(true);
    setTestResponse(null);
    try {
      const result = await jobsService.testExternalConnectorConnect(editing.configKey, buildTestRequest());
      setTestResponse({ kind: 'connect', result });
      if (result.success) {
        toast.success(`Kết nối OK — totalItems: ${result.totalItems}`);
      } else {
        toast.error(result.message || 'Test kết nối thất bại');
      }
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi test kết nối');
    } finally {
      setTestingConnect(false);
    }
  };

  const runTestSearch = async () => {
    if (!editing || !assertForTestSearch()) return;
    setTestingSearch(true);
    setTestResponse(null);
    try {
      const result = await jobsService.testExternalConnectorSearch(editing.configKey, buildTestRequest());
      setTestResponse({ kind: 'search', result });
      if (result.success) {
        if (result.totalItems > 0 && testFromDate && testToDate) {
          setLastSuccessfulTestByKey((prev) => ({
            ...prev,
            [editing.configKey]: {
              from: testFromDate,
              to: testToDate,
              totalItems: result.totalItems,
            },
          }));
        }
        toast.success(`Search OK — ${result.itemCount} item / total ${result.totalItems}`);
      } else {
        toast.error(result.message || 'Test search thất bại');
      }
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi test search');
    } finally {
      setTestingSearch(false);
    }
  };

  const runPreviewConvert = async (documentKey?: string | null) => {
    if (!editing || !assertForTestSearch()) return;
    setTestingPreview(true);
    if (!documentKey) {
      setPreviewResult(null);
    }
    try {
      const result = await jobsService.testExternalConnectorPreview(editing.configKey, {
        ...buildTestRequest(),
        documentKey: documentKey ?? null,
      });
      setPreviewResult(result);
      setPreviewDocumentKey(result.selectedDocumentKey ?? documentKey ?? null);
      if (result.success) {
        toast.success(
          documentKey
            ? `Preview convert — ${result.selectedDocumentKey}`
            : `Preview convert — ${result.searchItems.length} chứng từ search`,
        );
      } else {
        toast.error(result.message || 'Preview convert thất bại');
      }
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi preview convert');
    } finally {
      setTestingPreview(false);
    }
  };

  const handlePreviewSelectDocument = (documentKey: string) => {
    setPreviewDocumentKey(documentKey);
    void runPreviewConvert(documentKey);
  };

  const save = async () => {
    if (!editing || !assertConnectionDraft()) return;

    const merged = buildOptionsForSave(options, apiKeyInput, editing.optionsJson, hasStoredApiKey);

    setSaving(true);
    try {
      await jobsService.updateExternalSetConfig(editing.configKey, {
        ...form,
        optionsJson: serializeConnectorOptions(merged),
      });
      toast.success('Đã lưu cấu hình');
      closeEdit();
      load();
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi lưu');
    } finally {
      setSaving(false);
    }
  };

  const submitSyncRequest = async () => {
    if (!syncTarget) return;
    if (!syncFromDate || !syncToDate) {
      toast.error('Chọn Từ ngày và Đến ngày');
      return;
    }
    if (syncFromDate > syncToDate) {
      toast.error('Từ ngày không được lớn hơn Đến ngày');
      return;
    }

    setRunning(true);
    try {
      const res = await jobsService.triggerExternalSync(syncTarget.configKey, {
        fromDate: syncFromDate,
        toDate: syncToDate,
      });
      toast.success(
        `Đã tạo yêu cầu sync (${res.status}) · ${syncFromDate} → ${syncToDate} · theo dõi run ${res.runId.slice(0, 8)}…`,
      );
      setSyncTarget(null);
      navigate(`/admin/jobs/external-runs?runId=${res.runId}`);
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi tạo yêu cầu sync');
    } finally {
      setRunning(false);
    }
  };

  return (
    <div data-testid="data-sync-set-config-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
        {' · '}
        <Link to="/admin/jobs/external-runs">Theo dõi sync ngoài</Link>
        {' · '}
        <Link to="/admin/jobs/inbound">Inbound dashboard</Link>
      </p>
      <p style={{ color: '#555', marginBottom: 16 }}>
        Mọi tham số connector (URL, API key, pageSize, parallel, timeout, retry, ngày mặc định) được{' '}
        <strong>cấu hình và lưu trên UI</strong> — bảng <code>data_sync_set_configs</code>.
      </p>

      {syncTarget ? (
        <div style={{ marginBottom: 16 }}>
          <TableCard>
            <div style={{ padding: 16 }}>
              <h3 style={{ marginTop: 0 }}>Tạo yêu cầu sync — {syncTarget.configKey}</h3>
              <p style={{ color: '#666', fontSize: 14, marginBottom: 12 }}>
                Khoảng ngày gửi vào <code>criterias.fromDate</code> / <code>toDate</code> khi search REVA FM.
                {syncDateSource === 'override' ? (
                  <>
                    {' '}
                    <strong>Đang dùng ngày test / chọn thủ công.</strong>
                  </>
                ) : syncDateSource === 'lastTest' ? (
                  <>
                    {' '}
                    <strong>Đang dùng ngày từ lần test search OK gần nhất.</strong>
                  </>
                ) : syncDateSource === 'offset' ? (
                  <>
                    {' '}
                    <strong>Đang dùng offset/lookback (thường = hôm nay) — đổi ngày nếu test tab dùng khoảng khác.</strong>
                  </>
                ) : null}
              </p>
              <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'flex-end' }}>
                <Input
                  label="Từ ngày"
                  type="date"
                  value={syncFromDate}
                  onChange={(e) => setSyncFromDate(e.target.value)}
                  data-testid="sync-from-date"
                />
                <Input
                  label="Đến ngày"
                  type="date"
                  value={syncToDate}
                  onChange={(e) => setSyncToDate(e.target.value)}
                  data-testid="sync-to-date"
                />
                <Button type="button" onClick={submitSyncRequest} disabled={running}>
                  {running ? 'Đang gửi…' : 'Tạo yêu cầu sync'}
                </Button>
                <Button type="button" variant="secondary" onClick={() => setSyncTarget(null)}>
                  Hủy
                </Button>
              </div>
            </div>
          </TableCard>
        </div>
      ) : null}

      <div className={`${listStyles.shell} ${listStyles.shellWithIntro}`}>
        <TableCard
          listShell
          header={
            <div>
              <h2 className={listStyles.listHeaderTitle}>Connector sync ngoài</h2>
              <p className={listStyles.listHint}>
                Tìm theo mã connector, Base URL, search path hoặc khoảng ngày mặc định.
              </p>
              <JobsListToolbar
                searchQuery={searchQuery}
                onSearchChange={setSearchQuery}
                searchPlaceholder="Tìm connector…"
                searchTestId="connector-list-search"
                onRefresh={() => load()}
                refreshDisabled={loading}
                totalCount={rows.length}
                filteredCount={filteredRows.length}
                loading={loading}
                itemLabel="connector"
              />
            </div>
          }
        >
          <ExternalConnectorListGrid
            rows={filteredRows}
            loading={loading}
            searchQuery={searchQuery}
            onEdit={startEdit}
            onSync={openSyncRequest}
          />
        </TableCard>
      </div>

      <Slideout
        isOpen={Boolean(editing)}
        onClose={closeEdit}
        title={editing ? `Cấu hình connector — ${editing.configKey}` : ''}
        width={SLIDEOUT_WIDTH}
        data-testid="connector-config-edit-slideout"
        customFooter={
          <div className={styles.footerBtns}>
            <Button type="button" variant="secondary" onClick={closeEdit} disabled={saving}>
              Hủy
            </Button>
            <Button type="button" onClick={save} disabled={saving} data-testid="connector-save-btn">
              {saving ? 'Đang lưu…' : 'Lưu cấu hình'}
            </Button>
          </div>
        }
      >
        {editing ? (
          <ExternalConnectorConfigForm
            configKey={editing.configKey}
            form={form}
            options={options}
            apiKeyInput={apiKeyInput}
            hasStoredApiKey={hasStoredApiKey}
            activePanel={activePanel}
            testFromDate={testFromDate}
            testToDate={testToDate}
            testResponse={testResponse}
            testingConnect={testingConnect}
            testingSearch={testingSearch}
            testingPreview={testingPreview}
            onActivePanelChange={setActivePanel}
            onFormChange={setForm}
            onOptionsChange={setOptions}
            onApiKeyInputChange={setApiKeyInput}
            onTestFromDateChange={setTestFromDate}
            onTestToDateChange={setTestToDate}
            onTestConnect={runTestConnect}
            onTestSearch={runTestSearch}
            onTestPreview={() => runPreviewConvert(null)}
            onCreateSyncFromTest={openSyncWithTestDates}
            canCreateSyncFromTest={Boolean(editing?.hasApiKey)}
            lastTestTotalItems={editing ? lastSuccessfulTestByKey[editing.configKey]?.totalItems : undefined}
            previewPanel={
              <ExternalConnectorPreviewPanel
                configKey={editing.configKey}
                preview={previewResult}
                loading={testingPreview}
                selectedDocumentKey={previewDocumentKey}
                onSelectDocument={handlePreviewSelectDocument}
              />
            }
          />
        ) : null}
      </Slideout>
    </div>
  );
};

export default DataSyncSetConfigPage;
