import React from 'react';
import type { BffCleanupEntityScanRowDto } from '../../../services/admin/responseModel';
import styles from '../DataCleanupPage.module.css';

interface CleanupScanTableProps {
  entities: BffCleanupEntityScanRowDto[];
  totalDeletableRows: number;
}

const PHASE_LABELS: Record<number, string> = {
  1: 'Chi tiết CT',
  2: 'Audit entries',
  3: 'Chứng từ header',
  4: 'Sổ cái / kho',
  5: 'Event / job',
  6: 'Lịch sử CT',
  7: 'Bộ đếm mã',
};

export const CleanupScanTable: React.FC<CleanupScanTableProps> = ({
  entities,
  totalDeletableRows,
}) => {
  const deleteRows = entities
    .filter((e) => e.action === 'delete')
    .sort((a, b) => a.phase - b.phase || a.label.localeCompare(b.label, 'vi'));

  return (
    <div className={styles.previewTableWrapper}>
      <table className={styles.previewTable}>
        <thead>
          <tr>
            <th>Pha</th>
            <th>Nhóm</th>
            <th>Bảng / loại dữ liệu</th>
            <th className={styles.countCell}>Số bản ghi</th>
          </tr>
        </thead>
        <tbody>
          {deleteRows.map((row) => (
            <tr key={row.dbSetName} className={row.rowCount > 0 ? styles.hasData : styles.noData}>
              <td>{PHASE_LABELS[row.phase] ?? row.phase}</td>
              <td>{row.category}</td>
              <td>{row.label}</td>
              <td className={styles.countCell}>
                {row.rowCount > 0 ? (
                  <span className={styles.countBadge}>{row.rowCount.toLocaleString('vi-VN')}</span>
                ) : (
                  <span className={styles.countZero}>0</span>
                )}
              </td>
            </tr>
          ))}
        </tbody>
        <tfoot>
          <tr className={styles.totalRow}>
            <td colSpan={3}><strong>Tổng sẽ xóa</strong></td>
            <td className={styles.countCell}>
              <strong>{totalDeletableRows.toLocaleString('vi-VN')}</strong>
            </td>
          </tr>
        </tfoot>
      </table>
    </div>
  );
};
