import React, { useCallback, useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import { Pagination } from '../../../ui';
import { jobsService, type PlatformEventListItem } from '../../../services/jobs';
import { JobDetailCollapsibleSection } from './JobDetailMetaGrid';
import { JobEventsTable } from './JobEventsTable';
import { buildJobsEventsHref } from '../jobsEventLinks';
import { isEventActive } from '../jobStatusDisplay';
import { PlatformJobStatus } from '../platformJobStatus';
import styles from '../JobInternalPage.module.css';

const PAGE_SIZE = 20;

export type ExternalSyncRunEventsSectionProps = {
  runId: string;
  defaultOpen?: boolean;
};

export const ExternalSyncRunEventsSection: React.FC<ExternalSyncRunEventsSectionProps> = ({
  runId,
  defaultOpen = false,
}) => {
  const toast = useAppToast();
  const navigate = useNavigate();
  const [page, setPage] = useState(1);
  const [events, setEvents] = useState<PlatformEventListItem[]>([]);
  const [total, setTotal] = useState(0);
  const [filterLoading, setFilterLoading] = useState(false);
  const [pageLoading, setPageLoading] = useState(false);

  const loadPage = useCallback(
    async (targetPage: number, mode: 'filter' | 'page') => {
      if (mode === 'filter') setFilterLoading(true);
      else setPageLoading(true);
      try {
        const result = await jobsService.getEvents({
          page: targetPage,
          pageSize: PAGE_SIZE,
          direction: 'Inbound',
          runId,
        });
        setEvents(result.items);
        setTotal(result.total);
        setPage(targetPage);
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Không tải được events.';
        toast.error(message);
      } finally {
        if (mode === 'filter') setFilterLoading(false);
        else setPageLoading(false);
      }
    },
    [runId, toast],
  );

  useEffect(() => {
    void loadPage(1, 'filter');
  }, [runId, loadPage]);

  const hasActive = events.some((e) => isEventActive(e));
  const hasQueued = events.some(
    (e) => (e.jobStatus ?? e.processingStatus) === PlatformJobStatus.Queued || e.processingStatus === 'Pending',
  );
  useEffect(() => {
    if (!hasActive && !hasQueued) return undefined;
    const t = setInterval(() => void loadPage(page, 'page'), 4000);
    return () => clearInterval(t);
  }, [hasActive, hasQueued, page, loadPage]);

  const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));

  return (
    <JobDetailCollapsibleSection
      title={`Events Inbound (${total.toLocaleString('vi-VN')})`}
      defaultOpen={defaultOpen}
    >
      <p style={{ fontSize: 13, margin: '0 0 12px' }}>
        Sắp xếp mới nhất trước.{' '}
        <Link to={buildJobsEventsHref({ direction: 'Inbound', runId })}>
          Mở trang events đầy đủ →
        </Link>
      </p>
      <div className={pageLoading ? styles.gridBusy : undefined} aria-busy={pageLoading || undefined}>
        <div className={styles.eventsTableWrap}>
          {filterLoading ? (
            <p className={styles.gridLoading}>Đang tải…</p>
          ) : events.length === 0 ? (
            <p className={styles.gridEmpty}>Không có event Inbound cho run này.</p>
          ) : (
            <JobEventsTable
              events={events}
              selectedEventId={null}
              onSelectEvent={(eventId) =>
                navigate(buildJobsEventsHref({ direction: 'Inbound', runId, eventId }))
              }
            />
          )}
        </div>
      </div>
      {!filterLoading && total > 0 ? (
        <div style={{ marginTop: 12 }}>
          <Pagination
            currentPage={page}
            totalPages={totalPages}
            totalCount={total}
            pageSize={PAGE_SIZE}
            itemLabel="event"
            onPageChange={(next) => void loadPage(next, 'page')}
          />
        </div>
      ) : null}
    </JobDetailCollapsibleSection>
  );
};
