import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useNavTitle } from '@linm-soft-org/linm-web-common-components';
import { StatsCard, StatsCardsGrid, TableCard } from '../../ui';
import JobsListToolbar from './JobsListToolbar';
import { filterBySearchQuery } from './jobsListFilterUtils';
import styles from './JobInternalPage.module.css';
import { jobsService, type JobDirection, type PlatformJobDashboardStats } from '../../services/jobs';
import { JobEventTypeFilter } from './components/JobEventTypeFilter';
import { JobProgressBar } from './components/JobProgressBar';
import { JobEventFailReason } from './components/JobEventFailReason';
import { JobEventSkipInfo } from './components/JobEventSkipInfo';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import { buildJobsDirectionCardHref, buildJobsEventsHref } from './jobsEventLinks';

const directionTitles: Record<string, string> = {
  inbound: 'Inbound',
  outbound: 'Outbound',
  internal: 'Internal',
};

const JobDashboardPage: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const path = location.pathname.toLowerCase();
  const direction = (path.includes('/inbound')
    ? 'Inbound'
    : path.includes('/outbound')
      ? 'Outbound'
      : path.includes('/internal')
        ? 'Internal'
        : '') as JobDirection | '';

  const dirKey = path.includes('/inbound') ? 'inbound' : path.includes('/outbound') ? 'outbound' : '';
  useNavTitle(direction ? `Job dashboard — ${directionTitles[dirKey] ?? direction}` : 'Job dashboard');
  const toast = useAppToast();

  const [stats, setStats] = React.useState<PlatformJobDashboardStats[]>([]);
  const [eventTypes, setEventTypes] = React.useState<Awaited<ReturnType<typeof jobsService.getEventTypes>>>([]);
  const [eventType, setEventType] = React.useState('');
  const [status, setStatus] = React.useState('');
  const [events, setEvents] = React.useState<Awaited<ReturnType<typeof jobsService.getEvents>>['items']>([]);
  const [loading, setLoading] = React.useState(false);
  const [searchQuery, setSearchQuery] = React.useState('');

  const filteredEvents = React.useMemo(
    () =>
      filterBySearchQuery(events, searchQuery, (e) =>
        [
          e.eventType,
          e.processingStatus,
          e.runStatus ?? '',
          e.lastError ?? '',
          String(e.attemptCount),
          String(e.progressPercent),
          new Date(e.createdAt).toLocaleString('vi-VN'),
        ].join(' '),
      ),
    [events, searchQuery],
  );

  const load = React.useCallback(() => {
    setLoading(true);
    const t = setTimeout(() => {
      Promise.all([
        jobsService.getDashboard({ direction: direction || undefined, eventType: eventType || undefined }),
        jobsService.getEventTypes(direction || undefined),
        jobsService.getEvents({
          page: 1,
          pageSize: 25,
          direction: direction || undefined,
          eventType: eventType || undefined,
          processingStatus: status || undefined,
        }),
      ])
        .then(([dash, types, ev]) => {
          setStats(dash);
          setEventTypes(types);
          setEvents(ev.items);
        })
        .catch((e: Error) => toast.error(e.message))
        .finally(() => setLoading(false));
    }, 0);
    return () => clearTimeout(t);
  }, [direction, eventType, status, toast]);

  React.useEffect(() => load(), [load]);

  const hasProcessing = events.some((e) => e.processingStatus === 'Processing');
  React.useEffect(() => {
    if (!hasProcessing) return undefined;
    const t = setInterval(() => load(), 4000);
    return () => clearInterval(t);
  }, [hasProcessing, load]);

  const primary = React.useMemo(() => {
    if (direction) {
      return stats.find((s) => s.direction === direction) ?? stats[0];
    }
    const active = stats.filter((s) => !s.isPlaceholder);
    if (active.length === 0) return stats[0];
    return {
      direction: 'All',
      isPlaceholder: false,
      total: active.reduce((n, s) => n + s.total, 0),
      completed: active.reduce((n, s) => n + s.completed, 0),
      failed: active.reduce((n, s) => n + s.failed, 0),
      retryPending: active.reduce((n, s) => n + s.retryPending, 0),
      processing: active.reduce((n, s) => n + s.processing, 0),
      pending: active.reduce((n, s) => n + s.pending, 0),
      deadLetter: active.reduce((n, s) => n + s.deadLetter, 0),
    };
  }, [direction, stats]);

  const eventsScopeDirection = direction || undefined;

  const goEvents = React.useCallback(
    (status?: string) => {
      navigate(buildJobsEventsHref({ direction: eventsScopeDirection, status }));
    },
    [navigate, eventsScopeDirection],
  );

  return (
    <div data-testid="job-dashboard-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
        {' · '}
        <Link to="/admin/jobs/schedule">Cấu hình lịch</Link>
        {' · '}
        <Link to="/admin/jobs/external-sync">Cấu hình sync REVA</Link>
        {' · '}
        <Link to="/admin/jobs/external-runs">Theo dõi sync ngoài</Link>
        {' · '}
        <Link to="/admin/jobs/internal">Job nội bộ</Link>
      </p>

      <JobEventTypeFilter
        eventTypes={eventTypes}
        eventType={eventType}
        onEventTypeChange={setEventType}
        status={status}
        onStatusChange={setStatus}
      />

      {primary?.isPlaceholder ? (
        <p style={{ color: '#666', marginBottom: 16 }}>
          {'placeholderMessage' in primary ? primary.placeholderMessage : null}
        </p>
      ) : null}

      {primary && !primary.isPlaceholder ? (
        <StatsCardsGrid>
          <StatsCard
            label="Tổng"
            value={primary.total}
            variant="total"
            loading={loading}
            onClick={() => goEvents()}
          />
          <StatsCard
            label="Pass (Completed)"
            value={primary.completed}
            variant="success"
            loading={loading}
            onClick={() => goEvents('Completed')}
          />
          <StatsCard
            label="Fail"
            value={primary.failed}
            variant="danger"
            loading={loading}
            onClick={() => goEvents('Failed')}
          />
          <StatsCard
            label="Retry pending"
            value={primary.retryPending}
            variant="warning"
            loading={loading}
            onClick={() => goEvents('Failed')}
          />
          <StatsCard
            label="Processing"
            value={primary.processing}
            variant="warning"
            loading={loading}
            onClick={() => goEvents('Processing')}
          />
        </StatsCardsGrid>
      ) : null}

      {!direction && stats.length > 0 ? (
        <div style={{ marginTop: 24 }}>
          <h3>Theo hướng</h3>
          <StatsCardsGrid>
            {stats.map((s) => (
              <StatsCard
                key={s.direction}
                label={s.direction}
                value={s.isPlaceholder ? '—' : s.total}
                variant="total"
                loading={loading}
                onClick={
                  s.isPlaceholder
                    ? undefined
                    : () => navigate(buildJobsDirectionCardHref(s.direction))
                }
              />
            ))}
          </StatsCardsGrid>
        </div>
      ) : null}

      <div className={`${styles.shell} ${styles.shellBelowStats}`}>
        <TableCard
          listShell
          header={
            <div>
              <h4 className={styles.listHeaderTitle}>
                Event gần đây{' '}
                <Link to="/admin/jobs/events" style={{ fontSize: 14, fontWeight: 400 }}>
                  Xem tất cả →
                </Link>
              </h4>
              <p className={styles.listHint}>Tìm theo event type, status, run hoặc lỗi.</p>
              <JobsListToolbar
                searchQuery={searchQuery}
                onSearchChange={setSearchQuery}
                searchPlaceholder="Tìm event…"
                searchTestId="job-dashboard-events-search"
                onRefresh={load}
                refreshDisabled={loading}
                totalCount={events.length}
                filteredCount={filteredEvents.length}
                loading={loading}
                itemLabel="event"
              />
            </div>
          }
        >
          {loading ? (
            <p className={styles.gridLoading}>Đang tải…</p>
          ) : filteredEvents.length === 0 ? (
            <p className={styles.gridEmpty}>
              {searchQuery.trim() ? 'Không tìm thấy event phù hợp.' : 'Không có event'}
            </p>
          ) : (
            <div className={styles.gridWrap}>
              <table className={styles.gridTable}>
                <thead>
                  <tr>
                    <th align="left">Event type</th>
                    <th align="left">Status</th>
                    <th align="left">Tiến độ</th>
                    <th align="left">Skip / Fail set</th>
                    <th align="left">Lý do fail</th>
                    <th align="left">Attempt</th>
                    <th align="left">Created</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredEvents.map((e) => (
                    <tr key={e.eventId}>
                      <td>{e.eventType}</td>
                      <td>{e.processingStatus}</td>
                      <td>
                        <JobProgressBar
                          percent={e.progressPercent}
                          done={e.documentsDone}
                          total={e.documentsTotal}
                          unit={e.progressUnit}
                          compact
                        />
                      </td>
                      <td>
                        <JobEventSkipInfo
                          setsSkipped={e.setsSkipped}
                          setsFailed={e.setsFailed}
                          documentsTotal={e.documentsTotal}
                        />
                      </td>
                      <td>
                        <JobEventFailReason status={e.processingStatus} lastError={e.lastError} />
                      </td>
                      <td>
                        {e.attemptCount}/{e.maxAttempts}
                      </td>
                      <td>{new Date(e.createdAt).toLocaleString('vi-VN')}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </TableCard>
      </div>
    </div>
  );
};

export default JobDashboardPage;
