import type { JobDirection } from '../../services/jobs';

export function buildJobsEventsHref(options?: {
  direction?: JobDirection | '';
  status?: string;
  runId?: string;
  eventId?: string;
  eventType?: string;
}): string {
  const sp = new URLSearchParams();
  if (options?.direction) sp.set('direction', options.direction);
  if (options?.status) sp.set('status', options.status);
  if (options?.runId) sp.set('runId', options.runId);
  if (options?.eventId) sp.set('eventId', options.eventId);
  if (options?.eventType) sp.set('eventType', options.eventType);
  const q = sp.toString();
  return q ? `/admin/jobs/events?${q}` : '/admin/jobs/events';
}

/** Hub / dashboard direction cards → drill-down target. */
export function buildJobsDirectionCardHref(direction: string): string {
  if (direction === 'Internal') return '/admin/jobs/internal?tab=events';
  if (direction === 'Inbound') return buildJobsEventsHref({ direction: 'Inbound' });
  if (direction === 'Outbound') return buildJobsEventsHref({ direction: 'Outbound' });
  return '/admin/jobs/dashboard';
}
