import { useState, useEffect, useRef } from 'react';

/**
 * useMinLoadingTime
 *
 * Returns a `showLoading` boolean that stays `true` for at least `minMs`
 * milliseconds after loading begins.
 *
 * Problem it solves: when an API call is faster than ~300 ms the skeleton
 * loader flickers for one or two frames and disappears, creating jarring
 * visual jank.  By keeping `showLoading` true for a guaranteed minimum
 * the skeleton has time to register as intentional UI, not noise.
 *
 * Behaviour:
 *  - isLoading goes true  → showLoading = true immediately (no delay on start)
 *  - isLoading goes false → showLoading stays true for the remaining time
 *    needed to reach `minMs` since loading started, then flips to false
 *  - isLoading goes false after ≥ minMs have already elapsed → hides at once
 *
 * Usage:
 *   const showLoading = useMinLoadingTime(loading);         // default 300 ms
 *   const showLoading = useMinLoadingTime(loading, 500);    // custom 500 ms
 */
export function useMinLoadingTime(isLoading: boolean, minMs = 300): boolean {
  const [show, setShow] = useState(isLoading);
  const startedAt = useRef<number | null>(null);

  useEffect(() => {
    if (isLoading) {
      // Record when loading began and show immediately.
      startedAt.current = Date.now();
      setShow(true);
    } else {
      if (startedAt.current === null) {
        // Loading was never observed as true — hide straight away.
        setShow(false);
        return;
      }

      const elapsed   = Date.now() - startedAt.current;
      const remaining = minMs - elapsed;

      if (remaining <= 0) {
        // Minimum already satisfied — hide at once.
        setShow(false);
      } else {
        // Wait out the remaining time then hide.
        const id = setTimeout(() => setShow(false), remaining);
        return () => clearTimeout(id);
      }
    }
  }, [isLoading, minMs]);

  return show;
}
