import type { DataSyncSetConfigItem } from '../../services/jobs';
import { parseConnectorOptions } from './externalConnectorFormUtils';
import { filterBySearchQuery } from './jobsListFilterUtils';

export type ConnectorListRow = DataSyncSetConfigItem & {
  searchPath: string;
  defaultRangeLabel: string;
};

export const toConnectorListRow = (row: DataSyncSetConfigItem): ConnectorListRow => {
  const opt = parseConnectorOptions(row.optionsJson);
  const defaultRangeLabel =
    opt.defaultFromDate && opt.defaultToDate
      ? `${opt.defaultFromDate} → ${opt.defaultToDate}`
      : `Offset ${opt.dateOffsetDays}d / lookback ${opt.syncLookbackDays}d`;
  return {
    ...row,
    searchPath: opt.searchPath || '—',
    defaultRangeLabel,
  };
};

export const filterConnectorRows = (
  rows: ConnectorListRow[],
  query: string,
): ConnectorListRow[] =>
  filterBySearchQuery(rows, query, (r) =>
    [
      r.configKey,
      r.externalBaseUrl ?? '',
      r.searchPath,
      r.defaultRangeLabel,
      r.hasApiKey ? 'api key' : '',
      r.isEnabled ? 'bật có' : 'tắt không',
    ].join(' '),
  );
