/** Shared job/import status labels — delegates to platformJobStatus SSOT. */

import {
  isActiveJobStatus,
  jobStatusColor,
  jobStatusLabelVi,
  PlatformJobStatus,
  resolveEventJobStatus,
  resolveRunJobStatus,
} from './platformJobStatus';

export { jobStatusColor, PlatformJobStatus, jobStatusLabelVi };

export const displayJobStatus = (status: string): string => jobStatusLabelVi(status);

/** @deprecated Use displayJobStatus(resolveEventJobStatus(item)). */
export const displayEventStatus = (status: string): string => {
  if (status === 'Pending') return jobStatusLabelVi(PlatformJobStatus.Queued);
  if (status === 'Processing') return jobStatusLabelVi(PlatformJobStatus.Running);
  if (status === 'Completed') return jobStatusLabelVi(PlatformJobStatus.Done);
  if (status === 'DeadLetter') return jobStatusLabelVi(PlatformJobStatus.Failed);
  return jobStatusLabelVi(status);
};

/** External sync run status from BE → unified display. */
export const displayExternalRunStatus = (status: string): string => {
  if (status === 'Success') return jobStatusLabelVi(PlatformJobStatus.Done);
  if (status === 'Running') return jobStatusLabelVi(PlatformJobStatus.Running);
  return jobStatusLabelVi(status);
};

/** Checkpoint row status → unified display. */
export const displayCheckpointStatus = (status: string): string => {
  if (status === 'Skipped') return 'Đã có (skip)';
  if (status === 'Updated') return 'Cập nhật lại';
  if (status === 'Success' || status === 'Done') return 'Mới import';
  if (status === 'Pending') return jobStatusLabelVi(PlatformJobStatus.Queued);
  if (status === 'Processing') return jobStatusLabelVi(PlatformJobStatus.Running);
  return jobStatusLabelVi(status);
};

/** Voucher sample row — import outcome from isNewInsert. */
export const displayExternalVoucherImportOutcome = (isNewInsert?: boolean | null): string => {
  if (isNewInsert === true) return 'Mới';
  if (isNewInsert === false) return 'Đã có';
  return '?';
};

/** Import run status from BE → unified display. */
export const displayImportRunStatus = (status: string): string => {
  if (status === 'Success') return jobStatusLabelVi(PlatformJobStatus.Done);
  if (status === 'Skipped') return jobStatusLabelVi(PlatformJobStatus.Skipped);
  if (status === 'Running') return jobStatusLabelVi(PlatformJobStatus.Running);
  return jobStatusLabelVi(status);
};

/** Run status on event rows — unified display. */
export const displayLinkedRunStatus = (status: string): string => jobStatusLabelVi(status);

/** Prefer unified jobStatus when viewing event row/detail. */
export const resolveRunStatusFromEvent = (detail: {
  jobStatus?: string | null;
  processingStatus: string;
  runStatus?: string | null;
  runJobStatus?: string | null;
  nextRetryAt?: string | null;
  attemptCount: number;
  maxAttempts: number;
}): string | null => {
  const eventStatus = resolveEventJobStatus(detail);
  if (isActiveJobStatus(eventStatus)) return eventStatus;
  return resolveRunJobStatus(detail);
};

export const isJobRunningStatus = (status: string): boolean => isActiveJobStatus(status);

export const isEventActive = (item: {
  jobStatus?: string | null;
  processingStatus: string;
  nextRetryAt?: string | null;
  attemptCount?: number;
  maxAttempts?: number;
}): boolean => isActiveJobStatus(resolveEventJobStatus(item));

export const canRetryImportRun = (status: string): boolean =>
  status === 'Failed' || status === 'Partial';

export const incompleteExternalCheckpointCount = (summary: {
  failed: number;
  pending: number;
  processing: number;
}): number => summary.failed + summary.pending + summary.processing;

export const canStopExternalSyncRun = (status: string): boolean => status === 'Running';

/** Retry Pending/Failed/Processing after run stopped or finished with incomplete checkpoints. */
export const canRetryExternalSyncRun = (
  status: string,
  summary: { failed: number; pending: number; processing: number },
): boolean => status !== 'Running' && incompleteExternalCheckpointCount(summary) > 0;
