import React from 'react';
import { Link } from 'react-router-dom';
import type { PlatformEventQueueSummary } from '../../../services/jobs';
import { jobStatusColor, jobStatusLabelVi, PlatformJobStatus } from '../platformJobStatus';
import styles from '../JobInternalPage.module.css';

export type JobEventQueuePanelProps = {
  summary: PlatformEventQueueSummary | null;
  loading: boolean;
  direction?: string;
  onViewQueue: (eventType?: string, tier?: string) => void;
  onRefresh: () => void;
};

export const JobEventQueuePanel: React.FC<JobEventQueuePanelProps> = ({
  summary,
  loading,
  direction = 'Internal',
  onViewQueue,
  onRefresh,
}) => {
  if (loading && !summary) {
    return (
      <div className={styles.queuePanel} data-testid="job-event-queue-panel">
        <p style={{ margin: 0, fontSize: 13, color: '#64748b' }}>Đang tải hàng đợi…</p>
      </div>
    );
  }

  if (!summary) return null;

  const hasWork =
    summary.queuedTotal > 0 || summary.runningTotal > 0 || summary.retryPendingTotal > 0;

  return (
    <div className={styles.queuePanel} data-testid="job-event-queue-panel">
      <div className={styles.queuePanelHeader}>
        <strong>Hàng đợi platform events</strong>
        <button type="button" className={styles.linkButton} onClick={onRefresh}>
          Làm mới
        </button>
      </div>
      <div className={styles.queueStatsRow}>
        <button
          type="button"
          className={styles.queueStatChip}
          style={{ borderColor: jobStatusColor(PlatformJobStatus.Queued) }}
          onClick={() => onViewQueue()}
          data-testid="queue-stat-queued"
        >
          <span className={styles.queueStatLabel}>{jobStatusLabelVi(PlatformJobStatus.Queued)}</span>
          <span className={styles.queueStatValue} style={{ color: jobStatusColor(PlatformJobStatus.Queued) }}>
            {summary.queuedTotal.toLocaleString('vi-VN')}
          </span>
        </button>
        <button
          type="button"
          className={styles.queueStatChip}
          style={{ borderColor: jobStatusColor(PlatformJobStatus.Running) }}
          onClick={() => onViewQueue(undefined, undefined)}
          data-testid="queue-stat-running"
        >
          <span className={styles.queueStatLabel}>{jobStatusLabelVi(PlatformJobStatus.Running)}</span>
          <span className={styles.queueStatValue} style={{ color: jobStatusColor(PlatformJobStatus.Running) }}>
            {summary.runningTotal.toLocaleString('vi-VN')}
          </span>
        </button>
        {summary.retryPendingTotal > 0 ? (
          <button
            type="button"
            className={styles.queueStatChip}
            style={{ borderColor: jobStatusColor(PlatformJobStatus.RetryPending) }}
            onClick={() => onViewQueue()}
            data-testid="queue-stat-retry"
          >
            <span className={styles.queueStatLabel}>{jobStatusLabelVi(PlatformJobStatus.RetryPending)}</span>
            <span
              className={styles.queueStatValue}
              style={{ color: jobStatusColor(PlatformJobStatus.RetryPending) }}
            >
              {summary.retryPendingTotal.toLocaleString('vi-VN')}
            </span>
          </button>
        ) : null}
      </div>

      {!hasWork ? (
        <p style={{ margin: '8px 0 0', fontSize: 13, color: '#64748b' }}>Không có event đang chờ hoặc đang chạy.</p>
      ) : (
        <>
          {summary.byTier.length > 0 ? (
            <div className={styles.queueTierRow}>
              {summary.byTier.map((t) => (
                <span key={t.jobTier} className={styles.queueTierBadge}>
                  {t.jobTier}: {t.queuedCount} hàng đợi · {t.runningCount} chạy
                </span>
              ))}
            </div>
          ) : null}

          {summary.byEventType.length > 0 ? (
            <table className={styles.queueTable}>
              <thead>
                <tr>
                  <th align="left">Loại event</th>
                  <th align="right">Tier</th>
                  <th align="right">Hàng đợi</th>
                  <th align="right">Đang chạy</th>
                </tr>
              </thead>
              <tbody>
                {summary.byEventType.slice(0, 8).map((row) => (
                  <tr key={`${row.eventType}-${row.jobTier}`}>
                    <td>
                      <button
                        type="button"
                        className={styles.linkButton}
                        onClick={() => onViewQueue(row.eventType)}
                      >
                        {row.displayName ?? row.eventType}
                      </button>
                    </td>
                    <td align="right">{row.jobTier}</td>
                    <td align="right" style={{ color: jobStatusColor(PlatformJobStatus.Queued) }}>
                      {row.queuedCount.toLocaleString('vi-VN')}
                    </td>
                    <td align="right" style={{ color: jobStatusColor(PlatformJobStatus.Running) }}>
                      {row.runningCount.toLocaleString('vi-VN')}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : null}

          <p style={{ margin: '8px 0 0', fontSize: 12, color: '#64748b' }}>
            <Link
              to={`/admin/jobs/internal?tab=events&jobStatus=${PlatformJobStatus.Queued}&direction=${direction}`}
            >
              Xem toàn bộ hàng đợi →
            </Link>
          </p>
        </>
      )}
    </div>
  );
};
