import React from 'react';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import { jobsService, type AccountingPostControls } from '../../services/jobs';

const panelStyle: React.CSSProperties = {
  marginBottom: 16,
  padding: '12px 16px',
  border: '1px solid #e2e8f0',
  borderRadius: 8,
  background: '#fffbeb',
};

const rowStyle: React.CSSProperties = {
  display: 'flex',
  flexWrap: 'wrap',
  gap: 16,
  alignItems: 'flex-start',
  marginTop: 10,
};

const labelStyle: React.CSSProperties = {
  display: 'flex',
  gap: 8,
  alignItems: 'flex-start',
  fontSize: 13,
  maxWidth: 420,
  cursor: 'pointer',
};

export type AccountingPostControlsPanelProps = {
  controls: AccountingPostControls | null;
  loading: boolean;
  saving: boolean;
  onChange: (next: AccountingPostControls) => void;
  onReload: () => void;
};

const AccountingPostControlsPanel: React.FC<AccountingPostControlsPanelProps> = ({
  controls,
  loading,
  saving,
  onChange,
  onReload,
}) => (
  <div style={panelStyle} data-testid="accounting-post-controls-panel">
    <strong>Kiểm soát ghi sổ (import / re-post)</strong>
    <p style={{ margin: '4px 0 0', color: '#64748b', fontSize: 13 }}>
      Tạm dừng enqueue ghi sổ theo đơn vị (<code>X-Company-Id</code>). Ghi sổ thủ công trên ERP không bị ảnh hưởng.
    </p>
    {loading && !controls ? (
      <p style={{ margin: '8px 0 0', fontSize: 13 }}>Đang tải…</p>
    ) : controls ? (
      <div style={rowStyle}>
        <label style={labelStyle}>
          <input
            type="checkbox"
            checked={controls.importAutoPostPaused}
            disabled={saving}
            data-testid="post-control-import-paused"
            onChange={(e) =>
              onChange({ ...controls, importAutoPostPaused: e.target.checked })
            }
          />
          <span>
            <strong>Tạm dừng ghi sổ khi sync/import</strong>
            <br />
            <span style={{ color: '#64748b' }}>
              Không enqueue <code>Document.PostImportRequested</code> khi import REVA FM, master CSV,…
            </span>
          </span>
        </label>
        <label style={labelStyle}>
          <input
            type="checkbox"
            checked={controls.legacyRepostPaused}
            disabled={saving}
            data-testid="post-control-legacy-repost-paused"
            onChange={(e) =>
              onChange({ ...controls, legacyRepostPaused: e.target.checked })
            }
          />
          <span>
            <strong>Tạm dừng ghi sổ batch (PT/PC + HĐ CONGNO)</strong>
            <br />
            <span style={{ color: '#64748b' }}>
              Khóa «Ghi sổ tất cả» (phiếu <code>FM-*</code>) và «Ghi sổ HĐ thiếu CN».
            </span>
          </span>
        </label>
      </div>
    ) : (
      <p style={{ margin: '8px 0 0', fontSize: 13, color: '#b45309' }}>
        Không tải được cấu hình.{' '}
        <button type="button" onClick={onReload} style={{ textDecoration: 'underline', background: 'none', border: 0, cursor: 'pointer' }}>
          Thử lại
        </button>
      </p>
    )}
  </div>
);

/** Load + persist accounting post controls for external sync page. */
export const useAccountingPostControls = () => {
  const toast = useAppToast();
  const [controls, setControls] = React.useState<AccountingPostControls | null>(null);
  const [loading, setLoading] = React.useState(true);
  const [saving, setSaving] = React.useState(false);

  const load = React.useCallback(() => {
    setLoading(true);
    jobsService
      .getAccountingPostControls()
      .then(setControls)
      .catch((e: Error) => {
        toast.error(e.message);
        setControls(null);
      })
      .finally(() => setLoading(false));
  }, [toast]);

  React.useEffect(() => {
    load();
  }, [load]);

  const save = React.useCallback(
    (next: AccountingPostControls) => {
      const prev = controls;
      setControls(next);
      setSaving(true);
      jobsService
        .updateAccountingPostControls({
          importAutoPostPaused: next.importAutoPostPaused,
          legacyRepostPaused: next.legacyRepostPaused,
        })
        .then((saved) => {
          setControls(saved);
          toast.success(
            saved.importAutoPostPaused || saved.legacyRepostPaused
              ? 'Đã bật tạm dừng ghi sổ'
              : 'Đã cho phép ghi sổ import/re-post',
          );
        })
        .catch((e: Error) => {
          toast.error(e.message);
          if (prev) setControls(prev);
        })
        .finally(() => setSaving(false));
    },
    [controls, toast],
  );

  return { controls, loading, saving, load, save };
};

export default AccountingPostControlsPanel;
