import React from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useNavTitle } from '@linm-soft-org/linm-web-common-components';
import { Button, CatalogListPageTabs, Pagination, Slideout, TableCard, Tabs } from '../../ui';
import JobsListToolbar from './JobsListToolbar';
import { filterBySearchQuery } from './jobsListFilterUtils';
import {
  JOB_INTERNAL_TABS,
  resolveJobInternalTab,
  type JobInternalTabId,
} from '../../config/adminPages';
import { jobsService, type ImportRunDetail, type ImportRowError, type PlatformEventDetail } from '../../services/jobs';
import { JobEventTypeFilter } from './components/JobEventTypeFilter';
import { JobEventQueuePanel } from './components/JobEventQueuePanel';
import { JobEventQueueActions } from './components/JobEventQueueActions';
import { JobEventsTable, buildPlatformEventSearchText } from './components/JobEventsTable';
import { JobProgressBar } from './components/JobProgressBar';
import { JobEventDetailPanel } from './components/JobEventDetailPanel';
import { JobImportRunDetailPanel } from './components/JobImportRunDetailPanel';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import styles from './JobInternalPage.module.css';
import {
  aggregateRunRecordStats,
  formatImportRecordStatsLine,
  formatImportSetsSummaryLine,
  showImportRecordStats,
} from './importRunRecordStats';
import {
  canRetryImportRun,
  displayImportRunStatus,
  displayLinkedRunStatus,
  isEventActive,
  isJobRunningStatus,
  jobStatusColor,
} from './jobStatusDisplay';
import { PlatformJobStatus } from './platformJobStatus';
import type { PlatformEventQueueSummary } from '../../services/jobs';

const SLIDEOUT_WIDTH = '640px';
const EVENTS_PAGE_SIZE = 20;

const RUNNING_STATUSES = new Set(['Running']);

const formatDate = (iso: string) => new Date(iso).toLocaleString('vi-VN');

const escapeTsvCell = (value: string) => `"${value.replace(/"/g, '""')}"`;

const formatErrorSamplesTsv = (samples: ImportRowError[]) => {
  const header = ['Set', 'Catalog', 'Mã', 'RowKey', 'ErrorCode', 'Message', 'SuggestedAction', 'ActionLabelVi'];
  const rows = samples.map((e) =>
    [
      e.setName,
      e.catalog,
      e.code ?? '',
      e.rowKey,
      e.errorCode,
      e.message,
      e.suggestedAction,
      e.actionLabelVi ?? '',
    ]
      .map(escapeTsvCell)
      .join('\t'),
  );
  return [header.join('\t'), ...rows].join('\n');
};

const JobInternalPage: React.FC = () => {
  useNavTitle('Job nội bộ — import & event');
  const toast = useAppToast();
  const [searchParams, setSearchParams] = useSearchParams();
  const [tab, setTab] = React.useState<JobInternalTabId>(() =>
    resolveJobInternalTab(searchParams.get('tab')),
  );
  const [eventTypes, setEventTypes] = React.useState<Awaited<ReturnType<typeof jobsService.getEventTypes>>>([]);
  const [eventType, setEventType] = React.useState('');
  const [status, setStatus] = React.useState(() => searchParams.get('jobStatus') ?? '');
  const [queueSummary, setQueueSummary] = React.useState<PlatformEventQueueSummary | null>(null);
  const [loadingQueue, setLoadingQueue] = React.useState(false);
  const [events, setEvents] = React.useState<Awaited<ReturnType<typeof jobsService.getEvents>>['items']>([]);
  const [eventsTotal, setEventsTotal] = React.useState(0);
  const [eventsPage, setEventsPage] = React.useState(1);
  const [selectedEventId, setSelectedEventId] = React.useState<string | null>(searchParams.get('eventId'));
  const [eventDetail, setEventDetail] = React.useState<PlatformEventDetail | null>(null);
  const [loadingEventDetail, setLoadingEventDetail] = React.useState(false);
  const [runs, setRuns] = React.useState<Awaited<ReturnType<typeof jobsService.getImportRuns>>['items']>([]);
  const [selectedRunId, setSelectedRunId] = React.useState<string | null>(searchParams.get('runId'));
  const [runDetail, setRunDetail] = React.useState<ImportRunDetail | null>(null);
  const [loadingRunDetail, setLoadingRunDetail] = React.useState(false);
  const [retrying, setRetrying] = React.useState(false);
  const [copiedErrors, setCopiedErrors] = React.useState(false);
  const [linkedRunId, setLinkedRunId] = React.useState<string | null>(null);
  const [linkedRunDetail, setLinkedRunDetail] = React.useState<ImportRunDetail | null>(null);
  const [loadingLinkedRun, setLoadingLinkedRun] = React.useState(false);
  const [loading, setLoading] = React.useState(false);
  const [searchQuery, setSearchQuery] = React.useState('');

  React.useEffect(() => {
    const next = resolveJobInternalTab(searchParams.get('tab'));
    setTab((current) => (current === next ? current : next));
  }, [searchParams]);

  React.useEffect(() => {
    const runId = searchParams.get('runId');
    if (runId && runId !== selectedRunId) setSelectedRunId(runId);
  }, [searchParams, selectedRunId]);

  React.useEffect(() => {
    const eventId = searchParams.get('eventId');
    if (eventId && eventId !== selectedEventId) setSelectedEventId(eventId);
  }, [searchParams, selectedEventId]);

  const syncUrl = React.useCallback(
    (nextTab: JobInternalTabId, runId: string | null, eventId: string | null) => {
      const sp = new URLSearchParams();
      sp.set('tab', nextTab);
      if (runId) sp.set('runId', runId);
      if (eventId) sp.set('eventId', eventId);
      setSearchParams(sp, { replace: true });
    },
    [setSearchParams],
  );

  const handleTabChange = React.useCallback(
    (tabId: string) => {
      const next = resolveJobInternalTab(tabId);
      setTab(next);
      setEventType('');
      setStatus('');
      setSelectedRunId(null);
      setSelectedEventId(null);
      setSearchQuery('');
      syncUrl(next, null, null);
    },
    [syncUrl],
  );

  const loadQueueSummary = React.useCallback(() => {
    setLoadingQueue(true);
    jobsService
      .getEventQueueSummary({ direction: 'Internal', eventType: eventType || undefined })
      .then(setQueueSummary)
      .catch(() => setQueueSummary(null))
      .finally(() => setLoadingQueue(false));
  }, [eventType]);

  const loadEvents = React.useCallback(() => {
    jobsService
      .getEvents({
        page: eventsPage,
        pageSize: EVENTS_PAGE_SIZE,
        direction: 'Internal',
        eventType: eventType || undefined,
        jobStatus: status || undefined,
      })
      .then((r) => {
        setEvents(r.items);
        setEventsTotal(r.total);
      })
      .catch((e: Error) => toast.error(e.message));
  }, [eventsPage, eventType, status, toast]);

  const loadEventDetail = React.useCallback(
    (eventId: string) => {
      setLoadingEventDetail(true);
      return jobsService
        .getEvent(eventId)
        .then(setEventDetail)
        .catch((e: Error) => {
          toast.error(e.message);
          setEventDetail(null);
        })
        .finally(() => setLoadingEventDetail(false));
    },
    [toast],
  );

  const loadRuns = React.useCallback(() => {
    jobsService
      .getImportRuns(1, 20)
      .then((r) => setRuns(r.items))
      .catch((e: Error) => toast.error(e.message));
  }, [toast]);

  const loadRunDetail = React.useCallback(
    (runId: string) => {
      setLoadingRunDetail(true);
      return jobsService
        .getImportRun(runId)
        .then(setRunDetail)
        .catch((e: Error) => {
          toast.error(e.message);
          setRunDetail(null);
        })
        .finally(() => setLoadingRunDetail(false));
    },
    [toast],
  );

  const openImportRunSlideout = React.useCallback(
    (runId: string) => {
      setLinkedRunId(runId);
      setLoadingLinkedRun(true);
      jobsService
        .getImportRun(runId)
        .then(setLinkedRunDetail)
        .catch((e: Error) => {
          toast.error(e.message);
          setLinkedRunDetail(null);
        })
        .finally(() => setLoadingLinkedRun(false));
    },
    [toast],
  );

  const closeLinkedRunSlideout = React.useCallback(() => {
    setLinkedRunId(null);
    setLinkedRunDetail(null);
  }, []);

  React.useEffect(() => {
    setLoading(true);
    jobsService
      .getEventTypes('Internal')
      .then(setEventTypes)
      .finally(() => setLoading(false));
  }, []);

  React.useEffect(() => {
    if (tab === 'events') {
      loadEvents();
      loadQueueSummary();
    } else {
      loadRuns();
    }
  }, [tab, loadEvents, loadRuns, loadQueueSummary]);

  const hasActiveEvents = tab === 'events' && events.some((e) => isEventActive(e));
  const hasQueuedOnly =
    tab === 'events' &&
    events.some((e) => (e.jobStatus ?? e.processingStatus) === PlatformJobStatus.Queued || e.processingStatus === 'Pending');
  const hasRunningImports = tab === 'import' && runs.some((r) => isJobRunningStatus(r.status));
  React.useEffect(() => {
    if (!hasActiveEvents && !hasQueuedOnly && !hasRunningImports) return undefined;
    const t = setInterval(() => {
      if (tab === 'events') {
        loadEvents();
        loadQueueSummary();
      } else {
        loadRuns();
      }
    }, 4000);
    return () => clearInterval(t);
  }, [hasActiveEvents, hasQueuedOnly, hasRunningImports, tab, loadEvents, loadRuns, loadQueueSummary]);

  React.useEffect(() => {
    if (!selectedEventId) {
      setEventDetail(null);
      return undefined;
    }
    loadEventDetail(selectedEventId);
    const selected = events.find((e) => e.eventId === selectedEventId);
    if (!selected || !isEventActive(selected)) return undefined;
    const t = setInterval(() => {
      loadEventDetail(selectedEventId);
      loadEvents();
      loadQueueSummary();
    }, 4000);
    return () => clearInterval(t);
  }, [selectedEventId, events, loadEventDetail, loadEvents, loadQueueSummary]);

  React.useEffect(() => {
    setCopiedErrors(false);
  }, [selectedRunId]);

  React.useEffect(() => {
    if (!selectedRunId) {
      setRunDetail(null);
      return undefined;
    }
    loadRunDetail(selectedRunId);
    const selected = runs.find((r) => r.id === selectedRunId);
    if (!selected || !RUNNING_STATUSES.has(selected.status)) return undefined;
    const t = setInterval(() => {
      loadRunDetail(selectedRunId);
      loadRuns();
    }, 4000);
    return () => clearInterval(t);
  }, [selectedRunId, runs, loadRunDetail, loadRuns]);

  const handleSelectRun = (runId: string) => {
    setSelectedRunId(runId);
    syncUrl('import', runId, null);
  };

  const closeImportDetail = () => {
    setSelectedRunId(null);
    setRunDetail(null);
    syncUrl('import', null, null);
  };

  const handleSelectEvent = (eventId: string) => {
    setSelectedEventId(eventId);
    syncUrl('events', null, eventId);
  };

  const closeEventDetail = () => {
    setSelectedEventId(null);
    setEventDetail(null);
    syncUrl('events', null, null);
  };

  const handleViewQueue = React.useCallback(
    (nextEventType?: string, _tier?: string) => {
      const nextType = nextEventType ?? eventType;
      setTab('events');
      setEventType(nextType);
      setStatus(PlatformJobStatus.Queued);
      setEventsPage(1);
      const sp = new URLSearchParams();
      sp.set('tab', 'events');
      sp.set('jobStatus', PlatformJobStatus.Queued);
      if (nextType) sp.set('eventType', nextType);
      setSearchParams(sp, { replace: true });
    },
    [eventType, setSearchParams],
  );

  const handleRetryImport = () => {
    if (!selectedRunId || !runDetail) return;
    setRetrying(true);
    jobsService
      .retryImportRun(selectedRunId, true)
      .then((result) => {
        toast.success(`Đã enqueue retry — run mới ${result.runId.slice(0, 8)}…`);
        handleSelectRun(result.runId);
        loadRuns();
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setRetrying(false));
  };

  const handleCopyErrorSamples = React.useCallback(async () => {
    if (!runDetail?.errorSamples.length) return;
    try {
      await navigator.clipboard.writeText(formatErrorSamplesTsv(runDetail.errorSamples));
      setCopiedErrors(true);
      toast.success(`Đã copy ${runDetail.errorSamples.length} dòng lỗi (TSV — dán Excel)`);
      window.setTimeout(() => setCopiedErrors(false), 2000);
    } catch {
      toast.error('Không copy được — kiểm tra quyền clipboard trình duyệt');
    }
  }, [runDetail?.errorSamples, toast]);

  const filteredRuns = React.useMemo(
    () =>
      filterBySearchQuery(runs, searchQuery, (r) =>
        [
          r.id,
          r.status,
          displayImportRunStatus(r.status),
          r.trigger,
          formatDate(r.startedAtUtc),
          formatImportSetsSummaryLine(r.summary),
          showImportRecordStats(r.status)
            ? formatImportRecordStatsLine(aggregateRunRecordStats(r.summary))
            : '',
        ].join(' '),
      ),
    [runs, searchQuery],
  );

  const filteredEvents = React.useMemo(
    () => filterBySearchQuery(events, searchQuery, (e) => buildPlatformEventSearchText(e)),
    [events, searchQuery],
  );

  const renderImportDetail = () => {
    if (!selectedRunId) {
      return <p style={{ color: '#64748b' }}>Chọn một run để xem chi tiết.</p>;
    }
    return (
      <JobImportRunDetailPanel
        runDetail={runDetail}
        loading={loadingRunDetail}
        onCopyErrors={handleCopyErrorSamples}
        copiedErrors={copiedErrors}
      />
    );
  };

  const renderEventDetail = () => {
    if (!selectedEventId) {
      return <p style={{ color: '#64748b' }}>Chọn một event để xem chi tiết.</p>;
    }
    if (loadingEventDetail && !eventDetail) {
      return <p>Đang tải…</p>;
    }
    if (!eventDetail) {
      return <p style={{ color: '#64748b' }}>Không tải được chi tiết.</p>;
    }

    return (
      <JobEventDetailPanel
        detail={eventDetail}
        onOpenImportRun={openImportRunSlideout}
        onRequeued={() => {
          loadEvents();
          loadQueueSummary();
          if (selectedEventId) loadEventDetail(selectedEventId);
        }}
      />
    );
  };

  return (
    <div data-testid="job-internal-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
      </p>

      <CatalogListPageTabs data-testid="job-internal-tabs">
        <Tabs
          tabs={[...JOB_INTERNAL_TABS]}
          activeTab={tab}
          onTabChange={handleTabChange}
          variant="underline"
        />
      </CatalogListPageTabs>

      {tab === 'events' ? (
        <div className={styles.shell}>
          <JobEventQueuePanel
            summary={queueSummary}
            loading={loadingQueue}
            onViewQueue={handleViewQueue}
            onRefresh={loadQueueSummary}
          />
          <JobEventQueueActions
            eventType={eventType || undefined}
            queuedTotal={queueSummary?.queuedTotal ?? 0}
            onDone={() => {
              loadQueueSummary();
              loadEvents();
              if (selectedEventId) loadEventDetail(selectedEventId);
            }}
          />
          <TableCard
            listShell
            header={
              <div>
                <h4 className={styles.listHeaderTitle}>Sự kiện nội bộ ({eventsTotal})</h4>
                <p className={styles.listHint}>
                  Mới nhất trước — click dòng để xem chi tiết. Tìm theo runId, set import hoặc loại event.
                </p>
                <JobEventTypeFilter
                  eventTypes={eventTypes}
                  eventType={eventType}
                  onEventTypeChange={(v) => {
                    setEventType(v);
                    setEventsPage(1);
                  }}
                  status={status}
                  onStatusChange={(v) => {
                    setStatus(v);
                    setEventsPage(1);
                  }}
                />
                <JobsListToolbar
                  searchQuery={searchQuery}
                  onSearchChange={setSearchQuery}
                  searchPlaceholder="Tìm runId, set, event…"
                  searchTestId="job-internal-events-search"
                  onRefresh={loadEvents}
                  totalCount={events.length}
                  filteredCount={filteredEvents.length}
                  itemLabel="event"
                />
              </div>
            }
            footer={
              events.length > 0 ? (
                <Pagination
                  currentPage={eventsPage}
                  totalPages={Math.max(1, Math.ceil(eventsTotal / EVENTS_PAGE_SIZE))}
                  totalCount={eventsTotal}
                  pageSize={EVENTS_PAGE_SIZE}
                  itemLabel="event"
                  onPageChange={setEventsPage}
                />
              ) : undefined
            }
          >
            <div className={styles.eventsTableWrap}>
              {filteredEvents.length === 0 ? (
                <p className={styles.gridEmpty}>
                  {searchQuery.trim() ? 'Không tìm thấy event phù hợp.' : 'Không có event'}
                </p>
              ) : (
              <JobEventsTable
                events={filteredEvents}
                selectedEventId={selectedEventId}
                onSelectEvent={handleSelectEvent}
              />
              )}
            </div>
          </TableCard>
        </div>
      ) : (
        <div className={styles.shell}>
          <TableCard
            listShell
            header={
              <div>
                <h4 className={styles.listHeaderTitle}>Danh sách import</h4>
                <p className={styles.listHint}>
                  Danh sách cuộn — click một run để xem chi tiết / retry trong slide-out.
                </p>
                <JobsListToolbar
                  searchQuery={searchQuery}
                  onSearchChange={setSearchQuery}
                  searchPlaceholder="Tìm run import…"
                  searchTestId="job-internal-import-search"
                  onRefresh={loadRuns}
                  totalCount={runs.length}
                  filteredCount={filteredRuns.length}
                  loading={loading}
                  itemLabel="run"
                />
              </div>
            }
          >
            <ul className={styles.runList}>
              {filteredRuns.length === 0 ? (
                <li className={styles.gridEmpty}>
                  {searchQuery.trim() ? 'Không tìm thấy run phù hợp.' : 'Chưa có run import.'}
                </li>
              ) : null}
              {filteredRuns.map((r) => (
                <li key={r.id}>
                  <button
                    type="button"
                    onClick={() => handleSelectRun(r.id)}
                    className={`${styles.runItemBtn} ${
                      selectedRunId === r.id ? styles.runItemBtnSelected : ''
                    }`}
                  >
                    <strong style={{ color: jobStatusColor(r.status) }}>{displayImportRunStatus(r.status)}</strong> — {r.trigger}
                    <br />
                    <small>{formatDate(r.startedAtUtc)}</small>
                    <br />
                    <small>{formatImportSetsSummaryLine(r.summary)}</small>
                    {showImportRecordStats(r.status) ? (
                      <>
                        <br />
                        <small style={{ color: jobStatusColor(r.status), fontWeight: 600 }}>
                          {formatImportRecordStatsLine(
                            aggregateRunRecordStats(r.summary),
                          )}
                        </small>
                      </>
                    ) : null}
                    {r.progressPercent != null ? (
                      <>
                        <br />
                        <JobProgressBar
                          percent={r.progressPercent}
                          done={r.documentsDone}
                          total={r.documentsTotal}
                          compact
                        />
                      </>
                    ) : null}
                  </button>
                </li>
              ))}
            </ul>
          </TableCard>
        </div>
      )}

      <Slideout
        isOpen={tab === 'import' && Boolean(selectedRunId)}
        onClose={closeImportDetail}
        title="Chi tiết / tiến độ import"
        width={SLIDEOUT_WIDTH}
        data-testid="job-import-detail-slideout"
        customFooter={
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'flex-end', width: '100%' }}>
            {runDetail && canRetryImportRun(runDetail.status) ? (
              <Button type="button" variant="primary" disabled={retrying} onClick={handleRetryImport}>
                {retrying ? 'Đang enqueue…' : 'Retry import'}
              </Button>
            ) : null}
            <button type="button" className={styles.closeBtn} onClick={closeImportDetail}>
              Đóng
            </button>
          </div>
        }
      >
        <div className={styles.slideoutBody}>{renderImportDetail()}</div>
      </Slideout>

      <Slideout
        isOpen={tab === 'events' && Boolean(selectedEventId)}
        onClose={closeEventDetail}
        title="Chi tiết event"
        width={SLIDEOUT_WIDTH}
        data-testid="job-event-detail-slideout"
        customFooter={
          <button type="button" className={styles.closeBtn} onClick={closeEventDetail}>
            Đóng
          </button>
        }
      >
        <div className={styles.slideoutBody}>{renderEventDetail()}</div>
      </Slideout>

      <Slideout
        isOpen={Boolean(linkedRunId)}
        onClose={closeLinkedRunSlideout}
        title="Chi tiết / tiến độ import"
        width={SLIDEOUT_WIDTH}
        data-testid="job-event-linked-import-slideout"
        customFooter={
          <button type="button" className={styles.closeBtn} onClick={closeLinkedRunSlideout}>
            Đóng
          </button>
        }
      >
        <div className={styles.slideoutBody}>
          <JobImportRunDetailPanel
            runDetail={linkedRunDetail}
            loading={loadingLinkedRun}
            showEventsLink={false}
          />
        </div>
      </Slideout>
    </div>
  );
};

export default JobInternalPage;
