import { useEffect, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { isStandalone } from '../dev/isStandalone';

/**
 * Keeps MemoryRouter aligned with the browser address bar (single-spa shell nav).
 * Rule: web-app/rule/mfe-run-modes.md § Router Pattern
 */
export const MemoryRouterSync: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const locationRef = useRef(location);
  locationRef.current = location;

  const syncingFromWindowRef = useRef(false);

  useEffect(() => {
    const syncFromWindow = () => {
      const next = window.location.pathname + window.location.search;
      const current = locationRef.current.pathname + locationRef.current.search;
      if (next === current) return;
      syncingFromWindowRef.current = true;
      navigate(next, { replace: true });
    };

    window.addEventListener('single-spa:routing-event', syncFromWindow);
    window.addEventListener('popstate', syncFromWindow);
    return () => {
      window.removeEventListener('single-spa:routing-event', syncFromWindow);
      window.removeEventListener('popstate', syncFromWindow);
    };
  }, [navigate]);

  useEffect(() => {
    if (!isStandalone) return;
    if (syncingFromWindowRef.current) {
      syncingFromWindowRef.current = false;
      return;
    }

    const next = location.pathname + location.search;
    const current = window.location.pathname + window.location.search;
    if (next !== current) {
      window.history.replaceState(null, '', next);
    }
  }, [location.pathname, location.search]);

  return null;
};

export default MemoryRouterSync;
