/**
 * Admin local dev mount (`yarn start` + prod shell override): skip /admin/users/me/permissions.
 *
 * - `VITE_PERMISSIONS_LOCAL_MODE=true` in `.env` (webpack DefinePlugin)
 * - Dev server (`import.meta.env.DEV`): enabled unless `VITE_PERMISSIONS_LOCAL_MODE=false`
 */
export function isPermissionsLocalModeActive(): boolean {
  const flag = import.meta.env.VITE_PERMISSIONS_LOCAL_MODE;
  if (flag === 'true') return true;
  if (flag === 'false') return false;
  return String(import.meta.env.DEV) === 'true';
}
