import { useMemo } from 'react';
import { useFormOptions } from '@linm-soft-org/linm-web-common-components';

/** Active / inactive labels from BFF init-data (accounts-list form). */
export function useActiveStatusOptions() {
  const { accountStatusOptions, loading } = useFormOptions('accounts-list');

  const options = useMemo(() => {
    const active = accountStatusOptions.find((o) =>
      ['active', 'true', '1'].includes(String(o.value).toLowerCase()),
    );
    const inactive = accountStatusOptions.find((o) =>
      ['inactive', 'false', '0', 'disabled'].includes(String(o.value).toLowerCase()),
    );
    if (active && inactive) {
      return [
        { value: 'active', label: active.label },
        { value: 'inactive', label: inactive.label },
      ];
    }
    return accountStatusOptions;
  }, [accountStatusOptions]);

  const getActiveLabel = (isActive: boolean) => {
    const match = options.find((o) =>
      isActive
        ? ['active', 'true', '1'].includes(String(o.value).toLowerCase())
        : ['inactive', 'false', '0', 'disabled'].includes(String(o.value).toLowerCase()),
    );
    return match?.label ?? (isActive ? options[0]?.label : options[1]?.label) ?? '—';
  };

  return { options, loading, getActiveLabel };
}

/** HTTP methods for endpoint config (technical codes; labels from init when present). */
export function useHttpMethodOptions() {
  const { loading } = useFormOptions('admin-endpoints');
  const options = useMemo(
    () => [
      { value: 'GET', label: 'GET' },
      { value: 'POST', label: 'POST' },
      { value: 'PUT', label: 'PUT' },
      { value: 'PATCH', label: 'PATCH' },
      { value: 'DELETE', label: 'DELETE' },
    ],
    [],
  );
  return { options, loading };
}

/** Notification priority options — admin permissions tab. */
export function useNotificationPriorityOptions() {
  const { alertSeverityOptions, loading } = useFormOptions('admin-notifications');
  const options = useMemo(
    () =>
      alertSeverityOptions.length > 0
        ? alertSeverityOptions
        : [
            { value: 'Low', label: 'Low' },
            { value: 'Normal', label: 'Normal' },
            { value: 'High', label: 'High' },
            { value: 'Critical', label: 'Critical' },
          ],
    [alertSeverityOptions],
  );
  return { options, loading };
}
