import React from 'react';
import { Link } from 'react-router-dom';
import { Modal } from '../../../ui';
import { jobsService, type DataSyncCheckpointItem, type ExternalSyncDocumentErrorDetail } from '../../../services/jobs';
import { useAppToast } from '@linm-soft-org/linm-web-common-components';
import {
  JobDetailErrorBlock,
  JobDetailMetaGrid,
  JobDetailSection,
  formatJobDate,
  type JobDetailMetaItem,
} from './JobDetailMetaGrid';
import { connectorLabel } from '../externalSyncRunDisplay';
import { buildJobsEventsHref } from '../jobsEventLinks';
import { displayJobStatus, jobStatusColor } from '../jobStatusDisplay';
import { resolveEventJobStatus } from '../platformJobStatus';
import styles from '../JobInternalPage.module.css';

export type ExternalSyncCheckpointErrorModalProps = {
  isOpen: boolean;
  runId: string;
  checkpoint: DataSyncCheckpointItem | null;
  onClose: () => void;
};

const truncatePreview = (text: string, max = 120): string =>
  text.length <= max ? text : `${text.slice(0, max).trim()}…`;

export const ExternalSyncCheckpointErrorModal: React.FC<ExternalSyncCheckpointErrorModalProps> = ({
  isOpen,
  runId,
  checkpoint,
  onClose,
}) => {
  const toast = useAppToast();
  const [loading, setLoading] = React.useState(false);
  const [detail, setDetail] = React.useState<ExternalSyncDocumentErrorDetail | null>(null);

  React.useEffect(() => {
    if (!isOpen || !checkpoint) {
      setDetail(null);
      return;
    }

    let cancelled = false;
    setLoading(true);
    jobsService
      .getExternalDocumentError(runId, checkpoint.setName, checkpoint.documentKey)
      .then((d) => {
        if (!cancelled) setDetail(d);
      })
      .catch((e: Error) => {
        if (!cancelled) {
          toast.error(e.message);
          setDetail(null);
        }
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, [isOpen, runId, checkpoint, toast]);

  const message =
    detail?.message ??
    detail?.platformEvent?.lastError ??
    checkpoint?.errorMessage ??
    null;

  const overviewItems: JobDetailMetaItem[] = [
    { label: 'Loại', value: checkpoint ? connectorLabel(checkpoint.setName) : '—' },
    { label: 'Mã chứng từ', value: checkpoint?.documentKey ?? '—', mono: true },
    {
      label: 'Trạng thái checkpoint',
      value: checkpoint ? (
        <span style={{ color: jobStatusColor(checkpoint.status) }}>{checkpoint.status}</span>
      ) : (
        '—'
      ),
    },
    {
      label: 'Cập nhật checkpoint',
      value: formatJobDate(detail?.checkpointUpdatedAtUtc ?? checkpoint?.updatedAtUtc) ?? '—',
    },
    {
      label: 'Thời điểm lỗi',
      value: formatJobDate(detail?.atUtc ?? checkpoint?.errorAtUtc) ?? '—',
    },
  ];

  const event = detail?.platformEvent;

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={
        checkpoint
          ? `Lỗi chứng từ ${checkpoint.documentKey}`
          : 'Chi tiết lỗi chứng từ'
      }
      size="lg"
      stacked
    >
      {loading ? (
        <p style={{ color: '#64748b', margin: 0 }}>Đang tải chi tiết lỗi…</p>
      ) : (
        <>
          <JobDetailSection title="Tóm tắt">
            <JobDetailMetaGrid items={overviewItems} />
          </JobDetailSection>

          {message ? (
            <JobDetailErrorBlock
              error={message}
              category={event?.failureCategory}
              title="Thông báo lỗi"
              copyTestId="external-sync-error-copy"
            />
          ) : (
            <p style={{ color: '#64748b', fontSize: 13 }}>
              Không có thông báo lỗi đã lưu cho chứng từ này. Kiểm tra tab events Inbound hoặc chạy lại sync sau khi
              sửa cấu hình connector.
            </p>
          )}

          {event ? (
            <JobDetailSection title="Event xử lý (Inbound)">
              <JobDetailMetaGrid
                items={[
                  {
                    label: 'Event ID',
                    value: (
                      <Link
                        to={buildJobsEventsHref({
                          direction: 'Inbound',
                          runId: detail?.runId ?? runId,
                          eventId: event.eventId,
                        })}
                        className={styles.linkButton}
                      >
                        {event.eventId}
                      </Link>
                    ),
                    mono: true,
                    fullWidth: true,
                  },
                  {
                    label: 'Trạng thái',
                    value: (
                      <span style={{ color: jobStatusColor(resolveEventJobStatus(event)) }}>
                        {displayJobStatus(resolveEventJobStatus(event))}
                      </span>
                    ),
                  },
                  {
                    label: 'Attempt',
                    value: `${event.attemptCount}/${event.maxAttempts}`,
                  },
                  {
                    label: 'Tạo',
                    value: formatJobDate(event.createdAtUtc) ?? '—',
                  },
                  {
                    label: 'Xử lý',
                    value: formatJobDate(event.processedAtUtc) ?? '—',
                  },
                ]}
              />
              {event.lastError && event.lastError !== message ? (
                <JobDetailErrorBlock
                  error={event.lastError}
                  category={event.failureCategory}
                  title="Last error (event)"
                />
              ) : null}
            </JobDetailSection>
          ) : null}

          {event?.payloadJson ? (
            <details style={{ marginTop: 8 }}>
              <summary style={{ cursor: 'pointer', fontWeight: 600, fontSize: 13 }}>Payload JSON</summary>
              <pre
                style={{
                  marginTop: 8,
                  padding: 12,
                  background: '#f8fafc',
                  borderRadius: 8,
                  fontSize: 11,
                  overflow: 'auto',
                  maxHeight: 240,
                }}
              >
                {event.payloadJson}
              </pre>
            </details>
          ) : null}
        </>
      )}
    </Modal>
  );
};

export { truncatePreview as truncateExternalErrorPreview };
